#!/usr/bin/env python3
"""comprehensive_final.py — run from ~/LagnaMaster: python3 comprehensive_final.py"""
import os, re, ast
if not os.path.isfile("requirements.txt"):
    print("ERROR: run from LagnaMaster root"); exit(1)

def write(path, content, label):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w") as f: f.write(content)
    print(f"  WRITE {path} [{label}]")

def patch(path, old, new, label):
    if not os.path.isfile(path): print(f"  SKIP {path} [not found]"); return
    with open(path) as f: src = f.read()
    if old not in src: print(f"  SKIP {path} [{label}]"); return
    with open(path, "w") as f: f.write(src.replace(old, new, 1))
    print(f"  OK   {path} [{label}]")

def append_guard(path, text, guard, label):
    if not os.path.isfile(path): print(f"  SKIP {path} [not found]"); return
    with open(path) as f: src = f.read()
    if guard in src: print(f"  SKIP {path} [{label}]"); return
    with open(path, "a") as f: f.write("\n" + text)
    print(f"  OK   {path} [{label}]")

print("PART 1: Writing new modules...")
write('src/calculations/config_additions.py', '"""\nsrc/calculations/config_additions.py\nAyanamsha expansion (all 36 pyswisseph constants) + node mode toggle.\nSession 124 (Phase 1).\n\nSource: pyswisseph SE_SIDM_* constants; PVRNR recommends Lahiri/Chitrapaksha.\n"""\nfrom __future__ import annotations\nfrom dataclasses import dataclass\nfrom typing import Optional\n\n# ─── Complete Ayanamsha map ──────────────────────────────────────────────────\n# All 36 pyswisseph SE_SIDM_* constants\n# Format: {name: (pyswisseph_constant, description, school)}\n\nAYANAMSHA_MAP: dict[str, tuple[int, str, str]] = {\n    # Primary — most commonly used\n    "lahiri":           (1,  "Lahiri / Chitrapaksha — PVRNR, Govt of India standard", "parashari"),\n    "raman":            (3,  "BV Raman — Bangalore tradition", "parashari"),\n    "krishnamurti":     (5,  "KP / Krishnamurti — used in KP system", "kp"),\n    "djwhal_khul":      (6,  "Djwhal Khul", "western"),\n    "yukteshwar":       (7,  "Sri Yukteshwar — Autobiography of a Yogi", "parashari"),\n    "jn_bhasin":        (8,  "JN Bhasin", "parashari"),\n    "babyl_kugler1":    (11, "Babylonian — Kugler 1", "historical"),\n    "babyl_kugler2":    (12, "Babylonian — Kugler 2", "historical"),\n    "babyl_kugler3":    (13, "Babylonian — Kugler 3", "historical"),\n    "babyl_huber":      (14, "Babylonian — Huber", "historical"),\n    "babyl_etpsc":      (15, "Babylonian — ET/PSC", "historical"),\n    "aldebaran_15tau":  (16, "Aldebaran at 15 Taurus", "historical"),\n    "hipparchos":       (17, "Hipparchos", "historical"),\n    "sassanian":        (18, "Sassanian", "historical"),\n    "galcent_0sag":     (19, "Galactic Centre at 0 Sagittarius", "galactic"),\n    "j2000":            (20, "J2000.0", "astronomical"),\n    "j1900":            (21, "J1900.0", "astronomical"),\n    "b1950":            (22, "B1950.0", "astronomical"),\n    "suryasiddhanta":   (23, "Suryasiddhanta", "classical"),\n    "suryasiddhanta_mean": (24, "Suryasiddhanta (mean Sun)", "classical"),\n    "aryabhata":        (25, "Aryabhata", "classical"),\n    "aryabhata_mean":   (26, "Aryabhata (mean Sun)", "classical"),\n    "ss_revati":        (27, "SS Revati", "classical"),\n    "ss_citra":         (28, "SS Citra / True Chitrapaksha", "parashari"),\n    "true_citra":       (28, "True Citra — PVRNR preferred", "parashari"),  # alias\n    "true_revati":      (29, "True Revati", "classical"),\n    "true_pushya":      (30, "True Pushya — Sanjay Rath school", "jaimini"),\n    "galcent_rgilbrand": (31, "Galactic Centre (R. Gilbrand)", "galactic"),\n    "galequ_iau1958":   (32, "Galactic Equator IAU 1958", "galactic"),\n    "galequ_true":      (33, "True Galactic Equator", "galactic"),\n    "galequ_mula":      (34, "Galactic Equator — Mula", "galactic"),\n    "skydram":          (35, "Skydram (Mardyks)", "western"),\n    "true_mula":        (36, "True Mula", "jaimini"),\n    "dhruva_galcent":   (36, "Dhruva Galactic Centre", "galactic"),  # alias\n    "aryabhata_522":    (40, "Aryabhata 522", "classical"),\n    "babyl_britton":    (41, "Babylonian — Britton", "historical"),\n    "fagan_bradley":    (0,  "Fagan-Bradley — Western sidereal standard", "western"),\n}\n\n# Default for new charts — Lahiri is Govt of India standard, used by PVRNR\nDEFAULT_AYANAMSHA = "lahiri"\n\n# Ayanamshas where Lagna can differ by 1+ sign from Lahiri\n# (warn user if switching between these)\nLAGNA_SENSITIVE_AYANAMSHAS = {\n    "fagan_bradley", "yukteshwar", "raman", "true_citra",\n    "ss_revati", "true_revati", "galcent_0sag"\n}\n\n\ndef ayanamsha_constant(name: str) -> int:\n    """Return the pyswisseph SE_SIDM_* constant for a named ayanamsha."""\n    entry = AYANAMSHA_MAP.get(name.lower())\n    if entry is None:\n        raise ValueError(\n            f"Unknown ayanamsha: {name!r}. "\n            f"Valid names: {sorted(AYANAMSHA_MAP.keys())}"\n        )\n    return entry[0]\n\n\ndef is_lagna_sensitive(longitude: float, ayanamsha_name: str) -> bool:\n    """\n    Returns True if the Lagna is within 1° of a sign boundary,\n    meaning ayanamsha choice could change the Lagna sign.\n    Source: PLAN.md Session 124 note.\n    """\n    deg_in_sign = longitude % 30\n    return deg_in_sign < 1.0 or deg_in_sign >= 29.0\n\n\n# ─── Node mode ───────────────────────────────────────────────────────────────\n# Source: PVRNR (BPHS) uses mean node (Parashari standard)\n# KP and some modern practitioners use true node\n\nclass NodeMode:\n    MEAN = "mean"    # Mean node — Parashari standard (default)\n    TRUE = "true"    # True node — KP system, modern usage\n\n\nDEFAULT_NODE_MODE = NodeMode.MEAN\n\n# pyswisseph flags\nNODE_MODE_FLAGS: dict[str, int] = {\n    NodeMode.MEAN: 0,          # default — mean node\n    NodeMode.TRUE: 2048,       # SEFLG_TRUEPOS equivalent for nodes\n}\n\n# Max longitude difference between mean and true node\nNODE_MODE_MAX_DIFF_DEG = 1.5   # can reach 1.5° — enough to change sign at boundary\n\n\n@dataclass\nclass AstronomicalConfig:\n    """\n    Astronomical foundation configuration.\n    Stores ayanamsha + node mode for a calculation session.\n    """\n    ayanamsha: str = DEFAULT_AYANAMSHA\n    node_mode: str = DEFAULT_NODE_MODE\n\n    @property\n    def ayanamsha_constant(self) -> int:\n        return ayanamsha_constant(self.ayanamsha)\n\n    @property\n    def node_flag(self) -> int:\n        return NODE_MODE_FLAGS.get(self.node_mode, 0)\n\n    @property\n    def description(self) -> str:\n        entry = AYANAMSHA_MAP.get(self.ayanamsha.lower())\n        desc = entry[1] if entry else self.ayanamsha\n        return f"{desc} | Nodes: {self.node_mode}"\n\n\n# Default singleton for backward compatibility\nDEFAULT_CONFIG = AstronomicalConfig()\n', 'config_additions')
write('src/calculations/yogas_additions.py', '"""\nsrc/calculations/yogas_additions.py\nAdditional yoga definitions for Sessions 119 (Phase 1).\n\n- PM Yoga (Pancha Mahapurusha) with D9 strength check\n- Sunapha / Anapha / Durudhura (lunar yogas)\n- Vesi / Vasi / Ubhayachari (solar context yogas)\n- Solar Yoga node exclusion fix\n\nSources:\n  BPHS Ch.38 (Sunapha, Anapha, Durudhura)\n  BPHS Ch.37 (Vesi, Vasi, Ubhayachari — Rahu/Ketu excluded)\n  Phaladeepika Ch.6 v.20-28 (PM Yoga with D9)\n  Sanjay Rath, Crux of Vedic Astrology Ch.5 (Vargottama PM bonus)\n"""\n\nfrom __future__ import annotations\nfrom dataclasses import dataclass\nfrom typing import Optional\n\n# ─── Pancha Mahapurusha Yoga with D9 strength ────────────────────────────────\n\n# PM planets and their corresponding names\nPM_PLANETS: dict[str, str] = {\n    "Mars":    "Ruchaka",\n    "Mercury": "Bhadra",\n    "Jupiter": "Hamsa",\n    "Venus":   "Malavya",\n    "Saturn":  "Sasa",\n}\n\n# Exaltation signs for PM check\n_EXALT_SIGN = {\n    "Sun": 0, "Moon": 1, "Mars": 9, "Mercury": 5,\n    "Jupiter": 3, "Venus": 11, "Saturn": 6,\n}\n_OWN_SIGNS = {\n    "Mars": [0, 7], "Mercury": [2, 5], "Jupiter": [8, 11],\n    "Venus": [1, 6], "Saturn": [9, 10],\n}\n_SIGN_NAMES = [\n    "Aries", "Taurus", "Gemini", "Cancer", "Leo", "Virgo",\n    "Libra", "Scorpio", "Sagittarius", "Capricorn", "Aquarius", "Pisces"\n]\n\n\n@dataclass\nclass PMYogaResult:\n    planet: str\n    yoga_name: str\n    formation: str           # "exaltation" / "own_sign"\n    house: int               # Kendra house (1/4/7/10)\n    d9_strength: str         # "Vargottama" / "Strong" / "Standard" / "Weak"\n    d9_sign: int\n    effective: bool          # False if D9 debilitated or combust\n\n\ndef check_pm_yoga(planet: str, chart) -> Optional[PMYogaResult]:\n    """\n    Check Pancha Mahapurusha Yoga for one planet.\n    Conditions: planet in own/exalt sign AND in Kendra from Lagna.\n    D9 check: Vargottama = strongest; D9 debilitated = weak.\n    Source: Phaladeepika Ch.6 v.20-28; Sanjay Rath, Crux Ch.5\n    """\n    if planet not in PM_PLANETS or planet not in chart.planets:\n        return None\n\n    si = chart.planets[planet].sign_index\n    lon = chart.planets[planet].longitude\n    lagna_si = chart.lagna_sign_index\n\n    # Must be in own sign or exalted\n    in_own = si in _OWN_SIGNS.get(planet, [])\n    in_exalt = si == _EXALT_SIGN.get(planet)\n    if not (in_own or in_exalt):\n        return None\n\n    # Must be in Kendra (H1/H4/H7/H10) from Lagna\n    house = (si - lagna_si) % 12 + 1\n    if house not in (1, 4, 7, 10):\n        return None\n\n    # D9 strength assessment\n    try:\n        from src.calculations.vargas import compute_varga_sign\n        d9_si = compute_varga_sign(lon, 9)\n    except Exception:\n        d9_si = int(lon / 30) % 12  # fallback\n\n    # Vargottama: D1 sign == D9 sign\n    is_vargottama = (si == d9_si)\n\n    # D9 dignity\n    d9_in_own = d9_si in _OWN_SIGNS.get(planet, [])\n    d9_exalt = d9_si == _EXALT_SIGN.get(planet)\n    d9_debil_sign = (_EXALT_SIGN.get(planet, -1) + 6) % 12\n    d9_debil = (d9_si == d9_debil_sign)\n\n    if is_vargottama:\n        d9_strength = "Vargottama"\n    elif d9_exalt:\n        d9_strength = "Strong"\n    elif d9_in_own:\n        d9_strength = "Strong"\n    elif d9_debil:\n        d9_strength = "Weak"\n    else:\n        d9_strength = "Standard"\n\n    effective = d9_strength != "Weak"\n\n    return PMYogaResult(\n        planet=planet,\n        yoga_name=PM_PLANETS[planet],\n        formation="exaltation" if in_exalt else "own_sign",\n        house=house,\n        d9_strength=d9_strength,\n        d9_sign=d9_si,\n        effective=effective,\n    )\n\n\ndef detect_all_pm_yogas(chart) -> list[PMYogaResult]:\n    """Detect all five PM Yogas in a chart."""\n    results = []\n    for planet in PM_PLANETS:\n        result = check_pm_yoga(planet, chart)\n        if result:\n            results.append(result)\n    return results\n\n\n# ─── Sunapha / Anapha / Durudhura (Lunar yogas) ──────────────────────────────\n# Source: BPHS Ch.38; Phaladeepika Ch.6 v.50-55\n\n@dataclass\nclass LunarYogaResult:\n    yoga_name: str           # "Sunapha" / "Anapha" / "Durudhura" / "Kemadruma"\n    planets_involved: list[str]\n    description: str\n\n\ndef detect_lunar_yogas(chart) -> list[LunarYogaResult]:\n    """\n    Detect Sunapha, Anapha, Durudhura yogas.\n    Source: BPHS Ch.38\n\n    Sunapha: Planets in 2nd from Moon (Sun excluded)\n    Anapha: Planets in 12th from Moon (Sun excluded)\n    Durudhura: Planets in both 2nd AND 12th from Moon (Sun excluded)\n    """\n    if "Moon" not in chart.planets:\n        return []\n\n    moon_si = chart.planets["Moon"].sign_index\n    # Planets that count (Sun, Rahu, Ketu excluded)\n    eligible = ["Mars", "Mercury", "Jupiter", "Venus", "Saturn"]\n\n    second_from_moon  = (moon_si + 1) % 12   # 2nd sign\n    twelfth_from_moon = (moon_si - 1) % 12   # 12th sign\n\n    in_second  = [p for p in eligible if p in chart.planets\n                  and chart.planets[p].sign_index == second_from_moon]\n    in_twelfth = [p for p in eligible if p in chart.planets\n                  and chart.planets[p].sign_index == twelfth_from_moon]\n\n    results = []\n\n    if in_second and in_twelfth:\n        results.append(LunarYogaResult(\n            yoga_name="Durudhura",\n            planets_involved=in_second + in_twelfth,\n            description=f"Planets in 2nd ({\', \'.join(in_second)}) and 12th ({\', \'.join(in_twelfth)}) from Moon — native is wealthy, enjoys pleasures, has servants",\n        ))\n    elif in_second:\n        results.append(LunarYogaResult(\n            yoga_name="Sunapha",\n            planets_involved=in_second,\n            description=f"{\', \'.join(in_second)} in 2nd from Moon — native is self-made, wealthy, of good reputation",\n        ))\n    elif in_twelfth:\n        results.append(LunarYogaResult(\n            yoga_name="Anapha",\n            planets_involved=in_twelfth,\n            description=f"{\', \'.join(in_twelfth)} in 12th from Moon — native is handsome, renowned, generous, free from disease",\n        ))\n\n    return results\n\n\n# ─── Solar context yogas (Vesi / Vasi / Ubhayachari) ─────────────────────────\n# Source: BPHS Ch.37; Phaladeepika Ch.7 v.10-12\n# Note: Sun, Moon, Rahu, Ketu all EXCLUDED from Vesi/Vasi/Ubhayachari counts\n\n@dataclass\nclass SolarYogaResult:\n    yoga_name: str    # "Vesi" / "Vasi" / "Ubhayachari"\n    planets_involved: list[str]\n    nature: str       # "benefic" / "malefic" (depends on planet quality)\n    description: str\n\n\ndef detect_solar_yogas(chart) -> list[SolarYogaResult]:\n    """\n    Detect Vesi, Vasi, Ubhayachari yogas.\n    Source: BPHS Ch.37; Phaladeepika Ch.7 v.10-12\n\n    Eligible planets: Mars, Mercury, Jupiter, Venus, Saturn only\n    (Sun, Moon, Rahu, Ketu all excluded — per classical texts)\n\n    Vesi: Planets in 2nd from Sun\n    Vasi: Planets in 12th from Sun\n    Ubhayachari: Planets in both 2nd AND 12th from Sun\n    """\n    if "Sun" not in chart.planets:\n        return []\n\n    sun_si = chart.planets["Sun"].sign_index\n    # CRITICAL: Rahu/Ketu and Moon excluded — only classical 5 planets\n    eligible = ["Mars", "Mercury", "Jupiter", "Venus", "Saturn"]\n\n    second_from_sun  = (sun_si + 1) % 12\n    twelfth_from_sun = (sun_si - 1) % 12\n\n    in_second  = [p for p in eligible if p in chart.planets\n                  and chart.planets[p].sign_index == second_from_sun]\n    in_twelfth = [p for p in eligible if p in chart.planets\n                  and chart.planets[p].sign_index == twelfth_from_sun]\n\n    natural_benefics = {"Mercury", "Jupiter", "Venus"}\n    results = []\n\n    def _nature(planets: list[str]) -> str:\n        if all(p in natural_benefics for p in planets):\n            return "benefic"\n        if all(p not in natural_benefics for p in planets):\n            return "malefic"\n        return "mixed"\n\n    if in_second and in_twelfth:\n        results.append(SolarYogaResult(\n            yoga_name="Ubhayachari",\n            planets_involved=in_second + in_twelfth,\n            nature=_nature(in_second + in_twelfth),\n            description="Planets on both sides of Sun — native is eloquent, fortunate, respected",\n        ))\n    elif in_second:\n        results.append(SolarYogaResult(\n            yoga_name="Vesi",\n            planets_involved=in_second,\n            nature=_nature(in_second),\n            description=f"{\', \'.join(in_second)} in 2nd from Sun — benefic Vesi: diligent, truthful, balanced physique",\n        ))\n    elif in_twelfth:\n        results.append(SolarYogaResult(\n            yoga_name="Vasi",\n            planets_involved=in_twelfth,\n            nature=_nature(in_twelfth),\n            description=f"{\', \'.join(in_twelfth)} in 12th from Sun — benefic Vasi: fortunate, liberal, at peace",\n        ))\n\n    return results\n', 'yogas_additions')
write('src/calculations/sputa_drishti.py', '"""\nsrc/calculations/sputa_drishti.py\nSputa Drishti — exact degree-based aspect strength.\nSession 128 (Phase 2).\n\nClassical texts give aspectual influence as a function of the exact\nlongitudinal arc between aspector and aspected point.\n\nSources:\n  Saravali Ch.3 (aspect orbs and partial strengths)\n  Sarvartha Chintamani — aspectual strength table\n  BPHS Ch.26 v.1-10 (full/partial aspects)\n"""\n\nfrom __future__ import annotations\nfrom dataclasses import dataclass\nfrom math import sin, radians\n\n# ─── Aspect orb definitions ───────────────────────────────────────────────────\n# Each planet can cast a full (100%), three-quarter (75%), half (50%),\n# or quarter (25%) aspect depending on the arc from the aspector.\n#\n# Standard Parashari aspects:\n# - All planets: full aspect at 180° (7th house)\n# - Mars: additional full at 4th (90°) and 8th (210°)  — per BPHS 3/4 strength\n# - Jupiter: additional at 5th (120°) and 9th (240°)   — 3/4 strength\n# - Saturn: additional at 3rd (60°) and 10th (270°)    — 3/4 strength\n#\n# For Sputa Drishti, the strength varies smoothly with exact degrees\n\n@dataclass\nclass AspectResult:\n    aspector: str\n    aspected_longitude: float\n    arc_degrees: float       # 0-360 from aspector to aspected\n    strength: float          # 0.0 to 1.0\n    aspect_type: str         # "full" / "three_quarter" / "none"\n\n\n# House-based aspect strength table (BPHS Ch.26)\n# Keys: houses from aspector planet\n_ASPECT_TABLE: dict[str, dict[int, float]] = {\n    "Sun":     {7: 1.0},\n    "Moon":    {7: 1.0},\n    "Mars":    {4: 0.75, 7: 1.0, 8: 0.75},\n    "Mercury": {7: 1.0},\n    "Jupiter": {5: 0.75, 7: 1.0, 9: 0.75},\n    "Venus":   {7: 1.0},\n    "Saturn":  {3: 0.75, 7: 1.0, 10: 0.75},\n    "Rahu":    {7: 1.0, 5: 0.75, 9: 0.75},  # some schools give Rahu Jupiter-like aspects\n    "Ketu":    {7: 1.0, 4: 0.75, 8: 0.75},  # Ketu Mars-like aspects per some schools\n}\n\n# House-center degrees for orb calculation\n_HOUSE_CENTER_DEGREES: dict[int, float] = {\n    1: 0.0, 2: 30.0, 3: 60.0, 4: 90.0, 5: 120.0, 6: 150.0,\n    7: 180.0, 8: 210.0, 9: 240.0, 10: 270.0, 11: 300.0, 12: 330.0,\n}\n\n# Orb for aspect (degrees of arc before/after which aspect starts/fades)\nASPECT_ORB = 15.0   # degrees either side of exact aspect\n\n\ndef _arc(from_lon: float, to_lon: float) -> float:\n    """Arc in degrees from aspector to aspected (0-360, anticlockwise)."""\n    return (to_lon - from_lon) % 360.0\n\n\ndef _house_from_arc(arc: float) -> int:\n    """Whole-sign house count from arc (1-12)."""\n    return int(arc / 30) + 1\n\n\ndef sputa_drishti_strength(\n    aspector: str,\n    aspector_lon: float,\n    aspected_lon: float,\n    use_orbs: bool = True,\n) -> float:\n    """\n    Compute Sputa Drishti strength (0.0 to 1.0) between aspector and aspected.\n\n    When use_orbs=True: strength fades linearly within ±15° of exact aspect arc.\n    When use_orbs=False: returns full strength if within aspect house, 0.0 otherwise.\n\n    Source: Saravali Ch.3; BPHS Ch.26\n    """\n    aspect_table = _ASPECT_TABLE.get(aspector, {7: 1.0})\n    arc = _arc(aspector_lon, aspected_lon)\n    house = _house_from_arc(arc)\n\n    base_strength = aspect_table.get(house, 0.0)\n    if base_strength == 0.0:\n        # Check adjacent houses for orb effect\n        if not use_orbs:\n            return 0.0\n        # Check if near a valid aspect arc\n        max_nearby = 0.0\n        for asp_house, asp_str in aspect_table.items():\n            center = _HOUSE_CENTER_DEGREES[asp_house]\n            diff = min(abs(arc - center), 360 - abs(arc - center))\n            if diff < ASPECT_ORB:\n                fade = 1.0 - (diff / ASPECT_ORB)\n                max_nearby = max(max_nearby, asp_str * fade)\n        return round(max_nearby, 4)\n\n    if not use_orbs:\n        return base_strength\n\n    # Apply orb fade: full strength at center of house, fades at edges\n    center = _HOUSE_CENTER_DEGREES[house]\n    diff = min(abs(arc - center), 360 - abs(arc - center))\n    if diff <= ASPECT_ORB:\n        # Linear fade in last 15° of house arc (house = 30°, so fade in outer half)\n        fade_start = 15.0 - ASPECT_ORB / 2\n        if diff > fade_start:\n            fade = 1.0 - (diff - fade_start) / (ASPECT_ORB / 2)\n            return round(base_strength * max(0.0, fade), 4)\n\n    return base_strength\n\n\ndef compute_all_aspects(\n    planet: str,\n    planet_lon: float,\n    target_lons: dict[str, float],\n) -> list[AspectResult]:\n    """\n    Compute all aspects from a planet to a set of target longitudes.\n    Returns only aspects with strength > 0.\n    """\n    results = []\n    for target_name, target_lon in target_lons.items():\n        if target_name == planet:\n            continue\n        arc = _arc(planet_lon, target_lon)\n        strength = sputa_drishti_strength(planet, planet_lon, target_lon)\n        if strength > 0:\n            results.append(AspectResult(\n                aspector=planet,\n                aspected_longitude=target_lon,\n                arc_degrees=round(arc, 4),\n                strength=strength,\n                aspect_type="full" if strength >= 1.0 else "three_quarter",\n            ))\n    return results\n\n\ndef get_aspect_strength(aspector: str, houses_away: int) -> float:\n    """\n    Simple house-based aspect strength lookup.\n    houses_away: 1-12 counting from aspector\'s position.\n    Returns 0.0 if no aspect, else 0.75 or 1.0.\n    """\n    if houses_away == 7:\n        return 1.0\n    table = _ASPECT_TABLE.get(aspector, {7: 1.0})\n    return table.get(houses_away, 0.0)\n', 'sputa_drishti')
write('src/calculations/chara_karaka_config.py', '"""\nsrc/calculations/chara_karaka_config.py\nChara Karaka computation — 7-planet and 8-planet (Rahu) variants.\nSession 129 (Phase 2).\n\nChara Karakas are determined by the speed of planets in the chart.\nThe planet with the highest longitude degree in its sign = Atma Karaka (AK).\n\nSources:\n  Jaimini Sutras Adhyaya 1, Pada 1 (7-karaka system)\n  BPHS Ch.32 (8-karaka system including Rahu)\n  Sanjay Rath, Crux of Vedic Astrology Ch.6 (both systems with reconciliation)\n"""\n\nfrom __future__ import annotations\nfrom dataclasses import dataclass\nfrom enum import Enum\n\n# ─── Karaka names and order (by descending degree in sign) ───────────────────\n\nKARAKA_NAMES_7 = [\n    "AtmaKaraka",       # AK  — soul, self\n    "AmatyaKaraka",     # AmK — career, counsel\n    "BhratriKaraka",    # BK  — siblings, courage\n    "MatriKaraka",      # MK  — mother, mind\n    "PutraKaraka",      # PiK — children, intelligence\n    "GnatiKaraka",      # GK  — obstacles, disease\n    "DaraKaraka",       # DK  — spouse, partnerships\n]\n\nKARAKA_NAMES_8 = KARAKA_NAMES_7[:-1] + [\n    "PitraKaraka",      # PK  — father (8-karaka system only)\n    "DaraKaraka",       # DK  — spouse (shifted to 8th position)\n]\n\n# 7-karaka: Sun, Moon, Mars, Mercury, Jupiter, Venus, Saturn\n# 8-karaka: adds Rahu (uses 360 - Rahu\'s longitude to get degree in sign)\nPLANETS_7 = ["Sun", "Moon", "Mars", "Mercury", "Jupiter", "Venus", "Saturn"]\nPLANETS_8 = PLANETS_7 + ["Rahu"]\n\n\nclass KarakaSystem(str, Enum):\n    SEVEN  = "7"   # Standard Parashari/Jaimini — 7 planets\n    EIGHT  = "8"   # BPHS Ch.32 variant — includes Rahu as Pitru Karaka\n\n\n@dataclass\nclass CharaKarakaResult:\n    system: str                      # "7" or "8"\n    assignments: dict[str, str]      # {karaka_name: planet_name}\n    degrees: dict[str, float]        # {planet: degree_in_sign used for ranking}\n    atma_karaka: str                 # Convenience — the AK planet\n    dara_karaka: str                 # Convenience — the DK planet\n\n\ndef _degree_for_ranking(planet: str, chart) -> float:\n    """\n    Degree within sign used for Chara Karaka ranking.\n    For Rahu: use (30 - degree_in_sign) because Rahu moves retrograde.\n    Source: BPHS Ch.32; Sanjay Rath, Crux Ch.6\n    """\n    if planet not in chart.planets:\n        return 0.0\n    deg = chart.planets[planet].degree_in_sign % 30\n    if planet == "Rahu":\n        return 30.0 - deg   # Rahu\'s effective degree for ranking\n    return deg\n\n\ndef compute_chara_karakas(\n    chart,\n    system: str = KarakaSystem.SEVEN,\n) -> CharaKarakaResult:\n    """\n    Compute Chara Karakas for a chart.\n\n    7-planet system (Jaimini Sutras): Sun through Saturn\n    8-planet system (BPHS Ch.32): adds Rahu as Pitru Karaka\n\n    Source: Jaimini Sutras Adhyaya 1 Pada 1; BPHS Ch.32\n    """\n    if system == KarakaSystem.EIGHT:\n        planets = PLANETS_8\n        names = KARAKA_NAMES_8\n    else:\n        planets = PLANETS_7\n        names = KARAKA_NAMES_7\n\n    # Get degree in sign for each planet\n    degrees = {p: _degree_for_ranking(p, chart) for p in planets}\n\n    # Sort by descending degree — highest degree = most advanced = first karaka\n    ranked = sorted(\n        [p for p in planets if p in chart.planets],\n        key=lambda p: degrees[p],\n        reverse=True,\n    )\n\n    # Assign karaka names in order\n    assignments = {}\n    for i, planet in enumerate(ranked):\n        if i < len(names):\n            assignments[names[i]] = planet\n\n    return CharaKarakaResult(\n        system=str(system),\n        assignments=assignments,\n        degrees=degrees,\n        atma_karaka=assignments.get("AtmaKaraka", ""),\n        dara_karaka=assignments.get("DaraKaraka", ""),\n    )\n\n\n# ─── Karakamsha ───────────────────────────────────────────────────────────────\n\ndef compute_karakamsha(chart, chara_result: CharaKarakaResult) -> int:\n    """\n    Karakamsha Lagna: the D9 (navamsha) sign of the Atma Karaka.\n    Source: Jaimini Sutras Adhyaya 1 Pada 2\n    """\n    ak = chara_result.atma_karaka\n    if not ak or ak not in chart.planets:\n        return chart.lagna_sign_index\n\n    ak_lon = chart.planets[ak].longitude\n    try:\n        from src.calculations.vargas import compute_varga_sign\n        return compute_varga_sign(ak_lon, 9)\n    except Exception:\n        # Fallback\n        si = int(ak_lon / 30) % 12\n        pada = int((ak_lon % 30) * 9 / 30)\n        D9_START = {0: 0, 1: 9, 2: 6, 3: 3}\n        return (D9_START[si % 4] + pada) % 12\n\n\n# ─── Swamsha ─────────────────────────────────────────────────────────────────\n\ndef is_swamsha(chart, chara_result: CharaKarakaResult) -> bool:\n    """\n    Swamsha: AK in its own sign or exaltation in D9.\n    A very powerful placement — native is spiritually advanced.\n    Source: Jaimini Sutras; Sanjay Rath commentary\n    """\n    ak = chara_result.atma_karaka\n    if not ak or ak not in chart.planets:\n        return False\n\n    ak_lon = chart.planets[ak].longitude\n    try:\n        from src.calculations.vargas import compute_varga_sign\n        d9_si = compute_varga_sign(ak_lon, 9)\n    except Exception:\n        return False\n\n    from src.calculations.dignity import EXALT_SIGN, OWN_SIGNS\n    if d9_si in OWN_SIGNS.get(ak, []):\n        return True\n    if d9_si == EXALT_SIGN.get(ak):\n        return True\n    return False\n', 'chara_karaka_config')

